"use strict";
(function(){
	try{
		var root = document.documentElement;
		root.classList.add("theme-preload");

		if (!document.getElementById("biotern-theme-preload-style")) {
			var style = document.createElement("style");
			style.id = "biotern-theme-preload-style";
			style.textContent = "html.theme-preload *,html.theme-preload *::before,html.theme-preload *::after{transition:none!important;animation:none!important;}";
			document.head.appendChild(style);
		}

		function readCookie(name){
			var key = name + "=";
			var parts = document.cookie ? document.cookie.split(";") : [];
			for (var i = 0; i < parts.length; i++) {
				var chunk = parts[i].trim();
				if (chunk.indexOf(key) === 0) return chunk.substring(key.length);
			}
			return "";
		}

		var prefs = null;
		try {
			var raw = readCookie("biotern_theme_preferences");
			if (raw) prefs = JSON.parse(decodeURIComponent(raw));
		} catch (e) {}

		function getStored(modeKey, darkClass){
			var v = localStorage.getItem(modeKey) || "";
			return v.indexOf("dark") !== -1 || v === darkClass ? "dark" : "light";
		}

		var allowedFonts = [
			"app-font-family-inter",
			"app-font-family-lato",
			"app-font-family-rubik",
			"app-font-family-cinzel",
			"app-font-family-nunito",
			"app-font-family-roboto",
			"app-font-family-ubuntu",
			"app-font-family-poppins",
			"app-font-family-raleway",
			"app-font-family-system-ui",
			"app-font-family-noto-sans",
			"app-font-family-fira-sans",
			"app-font-family-work-sans",
			"app-font-family-open-sans",
			"app-font-family-maven-pro",
			"app-font-family-quicksand",
			"app-font-family-montserrat",
			"app-font-family-josefin-sans",
			"app-font-family-ibm-plex-sans",
			"app-font-family-source-sans-pro",
			"app-font-family-montserrat-alt",
			"app-font-family-roboto-slab"
		];

		var skin = prefs && (prefs.skin === "dark" || prefs.skin === "light")
			? prefs.skin
			: ((localStorage.getItem("app-skin-dark") || localStorage.getItem("app-skin") || localStorage.getItem("app_skin") || localStorage.getItem("theme") || "").indexOf("dark") !== -1 ? "dark" : "light");

		var navigation = prefs && (prefs.navigation === "dark" || prefs.navigation === "light")
			? prefs.navigation
			: getStored("app-navigation", "app-navigation-dark");

		var header = prefs && (prefs.header === "dark" || prefs.header === "light")
			? prefs.header
			: getStored("app-header", "app-header-dark");

		var font = prefs && typeof prefs.font === "string" ? prefs.font : (localStorage.getItem("font-family") || "default");

		if (skin === "dark") root.classList.add("app-skin-dark");
		if (navigation === "dark") root.classList.add("app-navigation-dark");
		if (header === "dark") root.classList.add("app-header-dark");

		if (font && font !== "default" && allowedFonts.indexOf(font) !== -1) {
			var cls = root.className || "";
			root.className = cls.replace(/\bapp-font-family-[^\s]+\b/g, "").replace(/\s{2,}/g, " ").trim();
			root.classList.add(font);
		}

		function getSavedMenuMode(){
			try{
				var menuState = localStorage.getItem("nexel-classic-dashboard-menu-mini-theme");
				if (menuState === "menu-mini-theme") return "mini";
				if (menuState === "menu-expend-theme") return "expanded";
			}catch(e){}
			return "auto";
		}

		function applySavedMenuMode(){
			var mode = getSavedMenuMode();
			var width = window.innerWidth || document.documentElement.clientWidth || 0;

			if (width <= 1024) {
				root.classList.remove("minimenu");
				return;
			}

			if (mode === "mini") {
				root.classList.add("minimenu");
				return;
			}

			if (mode === "expanded") {
				root.classList.remove("minimenu");
				return;
			}

			if (width >= 1024 && width <= 1600) {
				root.classList.add("minimenu");
			} else if (width > 1600) {
				root.classList.remove("minimenu");
			}
		}

		function syncMenuButtons(){
			var miniBtn = document.getElementById("menu-mini-button");
			var expandBtn = document.getElementById("menu-expend-button");
			if (!miniBtn || !expandBtn) return;

			if (root.classList.contains("minimenu")) {
				miniBtn.style.display = "none";
				expandBtn.style.display = "";
			} else {
				expandBtn.style.display = "none";
				miniBtn.style.display = "";
			}
		}

		function collapseExpandedMiniNav(){
			if (!root.classList.contains("minimenu")) return;
			var navItems = document.querySelectorAll(".nxl-navigation .nxl-item.nxl-hasmenu");
			for (var i = 0; i < navItems.length; i++) {
				var item = navItems[i];
				item.classList.remove("nxl-trigger", "active", "open");

				var children = item.children;
				for (var j = 0; j < children.length; j++) {
					var child = children[j];
					if (child.classList && child.classList.contains("nxl-link")) {
						child.classList.remove("nxl-trigger", "active", "open");
					}
					if (child.classList && child.classList.contains("nxl-submenu")) {
						child.style.display = "none";
					}
				}
			}
		}

		function resetExpandedNavState(){
			if (root.classList.contains("minimenu")) return;
			document.querySelectorAll(".nxl-navigation .nxl-item.nxl-hasmenu").forEach(function(item){
				item.classList.remove("nxl-trigger", "open");
			});
			document.querySelectorAll(".nxl-navigation .nxl-submenu").forEach(function(sm){
				sm.style.display = "none";
			});
		}

		function bindMiniNavCollapseHandlers(){
			var nav = document.querySelector(".nxl-navigation");
			if (!nav || nav.__bioternMiniNavBound) return;
			nav.__bioternMiniNavBound = true;

			nav.addEventListener("mouseleave", function(){
				if (!root.classList.contains("minimenu")) return;
				collapseExpandedMiniNav();
				var navContent = nav.querySelector(".navbar-content");
				if (navContent) {
					navContent.scrollTop = 0;
					if (navContent.firstElementChild && typeof navContent.firstElementChild.scrollTop === "number") {
						navContent.firstElementChild.scrollTop = 0;
					}
				}
			});
		}

		function bindMiniNavClickHandler(){
			var nav = document.querySelector(".nxl-navigation");
			if (!nav || nav.__bioternMiniNavClickBound) return;
			nav.__bioternMiniNavClickBound = true;

			function getDirectSubmenu(menuItem){
				if (!menuItem) return null;
				var children = menuItem.children;
				for (var i = 0; i < children.length; i++) {
					var child = children[i];
					if (child.classList && child.classList.contains("nxl-submenu")) {
						return child;
					}
				}
				return null;
			}

			function setMenuItemState(menuItem, shouldOpen){
				if (!menuItem || !menuItem.classList || !menuItem.classList.contains("nxl-hasmenu")) return;
				var submenu = getDirectSubmenu(menuItem);
				if (shouldOpen) {
					menuItem.classList.add("nxl-trigger");
					if (submenu) submenu.style.display = "block";
				} else {
					menuItem.classList.remove("nxl-trigger", "open");
					if (submenu) submenu.style.display = "none";
				}
			}

			nav.addEventListener("click", function(event){
				var desktop = (window.innerWidth || document.documentElement.clientWidth || 0) > 1024;
				if (!desktop) return;

				var link = event.target && event.target.closest ? event.target.closest(".nxl-item.nxl-hasmenu > .nxl-link") : null;
				if (!link) return;

				var menuItem = link.parentElement;
				if (!menuItem || !menuItem.classList.contains("nxl-hasmenu")) return;

				event.preventDefault();
				event.stopPropagation();
				if (event.stopImmediatePropagation) event.stopImmediatePropagation();

				var parentList = menuItem.parentElement;
				var wasOpen = menuItem.classList.contains("nxl-trigger");
				var isMini = root.classList.contains("minimenu");

				if (parentList && parentList.children) {
					for (var i = 0; i < parentList.children.length; i++) {
						var sibling = parentList.children[i];
						if (sibling !== menuItem) {
							setMenuItemState(sibling, false);
						}
					}
				}

				if (isMini) {
					if (!wasOpen) {
						setMenuItemState(menuItem, true);
					} else {
						setMenuItemState(menuItem, false);
					}
					return;
				}

				if (wasOpen) {
					setMenuItemState(menuItem, false);
				} else {
					setMenuItemState(menuItem, true);
				}
			}, true);
		}

		function bindMenuToggleButtons(){
			if (document.__bioternMenuToggleBound) return;
			document.__bioternMenuToggleBound = true;

			if (window.jQuery && typeof window.jQuery === "function") {
				try {
					window.jQuery("#menu-mini-button").off("click");
					window.jQuery("#menu-expend-button").off("click");
				} catch (e) {}
			}

			document.addEventListener("click", function(event){
				var target = event && event.target && event.target.closest ? event.target : null;
				if (!target) return;

				var miniBtn = target.closest("#menu-mini-button");
				var expandBtn = target.closest("#menu-expend-button");
				if (!miniBtn && !expandBtn) return;

				event.preventDefault();
				event.stopPropagation();
				if (event.stopImmediatePropagation) event.stopImmediatePropagation();

				if (miniBtn) {
					try { localStorage.setItem("nexel-classic-dashboard-menu-mini-theme", "menu-mini-theme"); } catch (e) {}
					applySavedMenuMode();
					syncMenuButtons();
					collapseExpandedMiniNav();
					return;
				}

				try { localStorage.setItem("nexel-classic-dashboard-menu-mini-theme", "menu-expend-theme"); } catch (e) {}
				applySavedMenuMode();
				syncMenuButtons();
				resetExpandedNavState();
			}, true);
		}

		function enforcePersistentMenu(){
			applySavedMenuMode();
			syncMenuButtons();
			collapseExpandedMiniNav();
		}

		applySavedMenuMode();

		document.addEventListener("DOMContentLoaded", function(){
			enforcePersistentMenu();
			bindMiniNavCollapseHandlers();
			bindMiniNavClickHandler();
			bindMenuToggleButtons();
			window.addEventListener("resize", function(){
				if (window.__bioternThemeMenuPersistTimer) {
					window.clearTimeout(window.__bioternThemeMenuPersistTimer);
				}
				window.__bioternThemeMenuPersistTimer = window.setTimeout(function(){
					enforcePersistentMenu();
				}, 0);
			});
			window.addEventListener("load", function(){
				enforcePersistentMenu();
			});
		});
	}catch(e){}
})();
